#!/usr/bin/env python3
import base64, os
print("Writing CodeDroid Ultra v3.0...")
data = base64.b64decode(
    ""
    ""
    ""
    ""
    ""
    ""
)
os.makedirs("src", exist_ok=True)
with open("src/App.jsx", "wb") as f:
    f.write(data)
print("SUCCESS! Size:", len(data), "bytes")
print("Now run: npm run build")
